import { supabaseAdmin } from '@/lib/supabase/admin';

export default async function CatalogPage() {
  const { data: products, error } = await supabaseAdmin
    .from('products')
    .select('id, name, price, description, warranty_days, max_claim_limit');

  if (error) {
    return <div className="p-8 text-red-500">Gagal memuat produk.</div>;
  }

  return (
    <div className="min-h-screen bg-gray-50 text-gray-900">
      <div className="max-w-5xl mx-auto p-6 md:p-12">
        <header className="mb-12 text-center">
          <h1 className="text-4xl font-black tracking-tight text-gray-900 mb-4">Yim Digital</h1>
          <p className="text-gray-500 max-w-xl mx-auto">Platform produk digital premium dengan garansi penggantian mandiri instan via Web dan Telegram.</p>
        </header>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {products?.map(p => (
            <div key={p.id} className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6 flex flex-col hover:shadow-md transition-shadow">
              <h2 className="text-xl font-bold mb-2">{p.name}</h2>
              <p className="text-3xl font-black text-indigo-600 mb-4">
                Rp {p.price.toLocaleString('id-ID')}
              </p>
              <div className="text-sm text-gray-600 mb-6 flex-grow">
                {p.description || 'Produk digital premium.'}
              </div>
              <div className="space-y-2 mb-6">
                <div className="flex justify-between items-center text-sm font-medium bg-blue-50 text-blue-700 px-3 py-2 rounded-lg">
                  <span>Garansi</span>
                  <span>{p.warranty_days} Hari</span>
                </div>
                <div className="flex justify-between items-center text-sm font-medium bg-purple-50 text-purple-700 px-3 py-2 rounded-lg">
                  <span>Limit Klaim</span>
                  <span>Maks {p.max_claim_limit}x</span>
                </div>
              </div>
              
              <form action="/api/checkout" method="POST">
                <input type="hidden" name="productId" value={p.id} />
                <button 
                  type="submit" 
                  className="w-full bg-gray-900 text-white font-semibold py-3 rounded-xl hover:bg-indigo-600 transition-colors"
                >
                  Beli Sekarang
                </button>
              </form>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}
